import random

suits = ["clubs", "spades", "hearts", "diamonds"]

values = ["ace", "2", "3", "4", "5", "6", "7", "8", "9", "10", "jack", "queen", "king"]

deck = [value + " of " + suit for value in values for suit in suits]

random.shuffle(deck)

player_hand = []
dealer_hand = []

player_hand.append(deck[0])
dealer_hand.append(deck[1])
player_hand.append(deck[2])
dealer_hand.append(deck[3])

player_points = 0
dealer_points = 0

for card in player_hand:
if card[0] == "a":
 player_points += 11
elif card[0] == "j" or card[0] == "q" or card[0] == "k":
 player_points += 10
else:
 player_points += int(card[0])

for card in dealer_hand:
if card[0] == "a":
 dealer_points += 11
elif card[0] == "j" or card[0] == "q" or card[0] == "k":
 dealer_points += 10
else:
 dealer_points += int(card[0])

if player_points > dealer_points:
 print("Player wins!")
elif dealer_points > player_points:
 print("Dealer wins!")
else:
 print("Draw!")
